'use client';
import { useEffect, useState, useRef } from 'react';
import { sb, UPLOAD_WORKER_URL } from '@/lib/supabase';

function fmt(s){if(!s||isNaN(s))return'0:00';return Math.floor(s/60)+':'+String(Math.floor(s%60)).padStart(2,'0');}
function sanitize(n){return n.replace(/[^a-zA-Z0-9._-]/g,'_');}
function fmtDate(d){if(!d)return'';const dt=new Date(d);const m=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];return m[dt.getMonth()]+' '+dt.getDate();}

const TONES=[
  {label:'Dark + Loud',short:'D+L',desc:'Heavy low end, maximum punch.'},
  {label:'Neutral + Loud',short:'N+L',desc:'Balanced and loud.'},
  {label:'Bright + Loud',short:'B+L',desc:'Aggressive and forward.'},
  {label:'Dark + Normal',short:'D+N',desc:'Warm, rich and cinematic.'},
  {label:'Neutral + Normal',short:'N+N',desc:'Balanced for all genres.'},
  {label:'Bright + Normal',short:'B+N',desc:'Clear and present.'},
  {label:'Dark + Gentle',short:'D+G',desc:'Warm and intimate.'},
  {label:'Neutral + Gentle',short:'N+G',desc:'Natural dynamics.'},
  {label:'Bright + Gentle',short:'B+G',desc:'Airy and delicate.'},
];
const DEFAULT_TONE=4;
function getToneMemory(n){try{const v=localStorage.getItem('mt_'+n.toLowerCase().replace(/\s+/g,'_'));return v!=null?parseInt(v):DEFAULT_TONE;}catch{return DEFAULT_TONE;}}
function setToneMemory(n,i){try{localStorage.setItem('mt_'+n.toLowerCase().replace(/\s+/g,'_'),i);}catch{}}
const FALLBACK_PEAKS=(()=>{const p=[];let s=0x12345678;for(let i=0;i<200;i++){s^=s<<13;s^=s>>17;s^=s<<5;s>>>=0;const e=Math.sin(i/200*Math.PI)*0.6+0.35;p.push(Math.max(0.05,Math.min(0.95,e*(0.45+s/0xFFFFFFFF*0.55))));}return p;})();
async function computePeaks(file,n=200){try{const ab=await file.arrayBuffer();const ac=new(window.AudioContext||window.webkitAudioContext)();const buf=await ac.decodeAudioData(ab);ac.close();const raw=buf.getChannelData(0),bs=Math.floor(raw.length/n),peaks=[];for(let i=0;i<n;i++){let max=0;const s=i*bs;for(let j=0;j<bs;j++){const v=Math.abs(raw[s+j]||0);if(v>max)max=v;}peaks.push(Math.min(1,max));}const mx=Math.max(...peaks)||1;return peaks.map(p=>Math.max(0.04,(p/mx)*0.95));}catch(e){return[];}}

function Waveform({peaks,progress,notes,duration,onSeek}){
  const canvasRef=useRef(null),rafRef=useRef(null),progressRef=useRef(progress);
  useEffect(()=>{progressRef.current=progress;},[progress]);
  const stablePeaks=useRef(FALLBACK_PEAKS);
  if(peaks&&peaks.length>4)stablePeaks.current=peaks;
  useEffect(()=>{
    const canvas=canvasRef.current;if(!canvas)return;
    const dpr=window.devicePixelRatio||1,W=canvas.parentElement?.offsetWidth||600,H=72;
    canvas.width=W*dpr;canvas.height=H*dpr;canvas.style.width=W+'px';canvas.style.height=H+'px';
    const ctx=canvas.getContext('2d');ctx.scale(dpr,dpr);
    const data=stablePeaks.current,BAR=2,GAP=1,STEP=BAR+GAP,numBars=Math.floor(W/STEP),cy=H/2;
    const heights=new Float32Array(numBars);
    for(let i=0;i<numBars;i++){const pi=Math.floor(i/numBars*data.length);heights[i]=Math.max(2,data[Math.min(pi,data.length-1)]*(cy-5));}
    const nc=document.createElement('canvas');nc.width=W;nc.height=H;
    const nctx=nc.getContext('2d');
    if(notes&&notes.length&&duration>0){notes.forEach(n=>{if(n.timestamp_sec==null||n.timestamp_sec>duration)return;const x=(n.timestamp_sec/duration)*W;nctx.save();nctx.strokeStyle='rgba(255,255,255,0.2)';nctx.lineWidth=1;nctx.setLineDash([2,3]);nctx.beginPath();nctx.moveTo(x,3);nctx.lineTo(x,H-3);nctx.stroke();nctx.restore();nctx.fillStyle='#e8a020';nctx.beginPath();nctx.arc(x,3,3,0,Math.PI*2);nctx.fill();});}
    let lastPlayX=-999;
    function draw(){const prog=Math.max(0,Math.min(1,progressRef.current||0)),playX=prog*W;if(Math.abs(playX-lastPlayX)>=.5){lastPlayX=playX;const cutBar=Math.floor(prog*numBars);ctx.clearRect(0,0,W,H);for(let i=0;i<numBars;i++){const h=heights[i];ctx.fillStyle=i<cutBar?'rgba(232,160,32,0.9)':'rgba(255,255,255,0.14)';ctx.fillRect(i*STEP,cy-h,BAR,h*2);}ctx.drawImage(nc,0,0);if(prog>.001){const px=Math.round(playX);ctx.save();ctx.shadowColor='rgba(232,160,32,0.8)';ctx.shadowBlur=8;ctx.fillStyle='#fff';ctx.fillRect(px-1,0,2,H);ctx.fillStyle='#ffcc44';ctx.beginPath();ctx.arc(px,3,4,0,Math.PI*2);ctx.fill();ctx.restore();}}rafRef.current=requestAnimationFrame(draw);}
    draw();return()=>{if(rafRef.current)cancelAnimationFrame(rafRef.current);};
  },[notes,duration]);
  return(<div onClick={e=>{if(!onSeek)return;const r=e.currentTarget.getBoundingClientRect();onSeek(Math.max(0,Math.min(1,(e.clientX-r.left)/r.width)));}} style={{width:'100%',height:72,cursor:'crosshair',userSelect:'none',WebkitUserSelect:'none'}}><canvas ref={canvasRef} style={{display:'block',width:'100%',height:72}}/></div>);
}

// Scroll stays unlocked — menu recalculates position on scroll so it stays anchored
// Close by: clicking same button again, choosing an action, or clicking a different ⋯
function FixedDropdown({anchorRef,open,onClose,children}){
  const [pos,setPos]=useState({top:0,right:0});
  function recalc(){if(!anchorRef.current)return;const rect=anchorRef.current.getBoundingClientRect();setPos({top:rect.bottom+4,right:window.innerWidth-rect.right});}
  useEffect(()=>{
    if(!open)return;
    recalc();
    window.addEventListener('scroll',recalc,true);
    return()=>{window.removeEventListener('scroll',recalc,true);};
  },[open]);
  if(!open)return null;
  return(<><div style={{position:'fixed',inset:0,zIndex:998,background:'transparent'}} onClick={onClose}/><div style={{position:'fixed',top:pos.top,right:pos.right,zIndex:999,background:'var(--surf2)',border:'1px solid var(--border2)',borderRadius:10,minWidth:176,boxShadow:'0 8px 40px rgba(0,0,0,.6)',overflow:'hidden'}}>{children}</div></>);
}

function ToneGrid({value,usedTones=[],onChange,onSetAll,showSetAll}){
  const [hov,setHov]=useState(null);
  const tip=TONES[hov!=null?hov:value!=null?value:DEFAULT_TONE];
  return(
    <div className="tgm-wrap">
      <div className="tgm-axes"><span>← Darker</span><span style={{margin:'0 auto',color:'var(--amber)',fontWeight:500,fontSize:10}}>TONE GRID</span><span>Brighter →</span></div>
      <div style={{display:'flex',gap:6,alignItems:'flex-start'}}>
        <div className="tgm-row-labels"><div>Louder</div><div>Normal</div><div>Gentler</div></div>
        <div className="tgm-grid">
          {TONES.map((t,i)=>{const used=usedTones.includes(i);return(
            <button key={i} className={'tgm-cell'+(i===value?' active':'')+(i===4?' center':'')+(used?' used':'')} onMouseEnter={()=>!used&&setHov(i)} onMouseLeave={()=>setHov(null)} onClick={()=>!used&&onChange(i)} disabled={used}>
              <span>{t.short}</span>{used&&<span className="tgm-used-dot">✓</span>}
            </button>
          );})}
        </div>
      </div>
      <div className="tgm-tip">{tip&&<><span className="tgm-tip-label">{tip.label}</span><span className="tgm-tip-desc">{tip.desc}</span></>}</div>
      {usedTones.length>0&&<div style={{fontSize:10,color:'var(--t3)',marginTop:6}}>✓ Already mastered — greyed cells unavailable</div>}
      {showSetAll&&<button className="tgm-set-all" onClick={()=>onSetAll&&onSetAll(value)}>Apply to all tracks</button>}
    </div>
  );
}
